    #[00:00 - 6:59]
    def morning_limit(t):
	    return (t.hour <= 6 and t.minute <= 59)

    #[22:01 - 23:59]
    def night_limit(t):
	    return (t.hour >= 22 and t.minute > 0)

    def adjust_time(t, requester):
	    if morning_limit(t):
		    if not requester:
			    t = t.replace(hour=7)
		    else:
			    t = t.replace(hour=7, minute=0)
	    if night_limit(t):
