    def total_weekends(time_agn, time_req):
	    fromdate = date(time_req.year, time_req.month, time_req.day)
	    todate = date(time_agn.year, time_agn.month, time_agn.day)
	    daygenerator = (fromdate + timedelta(x + 1) for x in xrange((todate - fromdate).days))
	    return sum(1 for day in daygenerator if day.weekday() >= 5)

    def total_days(time_agn, time_req):
	    fromdate = date(time_req.year, time_req.month, time_req.day)
	    todate = date(time_agn.year, time_agn.month, time_agn.day)
	    daygenerator = (fromdate + timedelta(x + 1) for x in xrange((todate - fromdate).days))
	    return sum(1 for day in daygenerator if day.weekday() < 5)


