#!/usr/bin/env python
# -*- encoding: utf-8 -*-
# Created on 2018-06-08 10:16:24
# Project: debug1

from pyspider.libs.base_handler import *
import re
import sys
reload(sys)
sys.setdefaultencoding('utf8')


CRAWL_DOMAINS =["zj.people.com.cn"]

def is_crawl_page(url):
    year = re.match(r'.*people.com.cn/n/([0-9]*)/.*', url)
    if url.startswith("http://comments.people.com.cn"): return False
    if year and int(year.group(1)) < 2017: return False # page is too old, no crawl.
    return True if [ul for ul in CRAWL_DOMAINS if ul in url] else False

def max_str_in_list(li):
    middle = map(len, li)
    return li[middle.index(max(middle))]

# sub special script show player
def spc(content):
    content = re.sub(r'showPlayer\(\{.*;', '', str(content)) if content else ''
    content = re.sub(r'var url =.*"\);\s*\}', '', str(content)) if content else ''
    content = re.sub(r'var zhaiyao=.*\);\s*\}\s*\}', '', str(content)) if content else ''
    return re.sub(r'var zhaiyao=.*c\[2\];\s*\}', '', str(content)) if content else ''


class Handler(BaseHandler):
    crawl_config = {
         "headers":{
             "User-Agent": "Mozilla/5.0 (Macintosh; Intel Mac OS X 10_13_4) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/69.0.3451.0 Safari/537.36",
         },
        #'proxy': '127.0.0.1:3128'
    }

    @every(minutes=24 * 60)
    def on_start(self):
        self.crawl('http://www.people.com.cn/', callback=self.index_page)

    @config(age=365 * 24 * 60 * 60)
    def index_page(self, response):
        for each in response.doc('a[href^="http"]').items():
            if not is_crawl_page(each.attr.href):
                continue
            self.crawl(each.attr.href, callback=self.detail_page, fetch_type='js')

    @config(priority=2)
    def detail_page(self, response):
        for each in response.doc('a[href^="http"]').items():
            if not is_crawl_page(each.attr.href):
                continue
            self.crawl(each.attr.href, callback=self.detail_page)
        c1 = response.doc('.box_con > p:not(script)').text()
        c2 = response.doc('.content > p ').text() or \
                response.doc('.fbody').text()
        c3 = response.doc('.text_c > p > :not(script)').text()
        c4 = response.doc('.show_text > p').text() or response.doc('.show_text').text()
        c5 = response.doc('.detail-p > p').text()
        c6 = response.doc('.artDet > p').text()
        c7 =  response.doc('#p_content').text()
        #print c7
        c8 = ''
        if response.doc('#p_content > p').items():
            #print '------------ in content ----------------'
            c8 = "".join([c.text() for c in response.doc('#p_content > p').items() if not c(':has(script)')])
            c7 = c8 or c7
        content = max_str_in_list([c1,c2,c3,c4,c5,c6,c7,c8])
        if spc(content.strip()):
            cate = response.doc('#rwb_navpath > a').text() or \
                    response.doc('.clink').text() or  \
                    response.doc('#p_navigator > a').text() or \
                    response.doc('.pos_re_search > a').text()
            cate_items = list(response.doc('table').items()) if response.doc('table').items() else []
            cate1 = cate_items[0] if len(cate_items) > 1 else ''
            cate = cate or cate1
            #print cate
            # cate = cate.split()[-1] if [x for x in cate.split() if x] else ''
            return {
                "url": response.url,
                "title": response.doc('title').text().replace('--人民网',''),
                "cate": cate,
                "content": spc(content),
                "tags": "",
                "save_database": True,
            }
        else:
            if is_crawl_page(response.url):
                self.crawl(response.url, callback=self.index_page)

@poconbhui Thanks! I think `REL_WHEEL = trackpad_touch1_y` works nicely. Do you know if it's possible to invert the direction?

But we should still implement proper two finger scrolling. `touch1` means the second finger. So the first finger still controls the mouse and the second finger controls scrolling at the same time. That works quite nicely, but it's not as good as real two finger scrolling on most laptops.

We should detect if both fingers are moving together and then use the average for scrolling. The mouse cursor should not move when doing a two finger scroll. Also, we should research if it possible to do the more fine grained scrolling instead of mouse wheel button events.

