@decor()
def func(*args):
    pass


class decor(object):
    INSTANCES_PATHS = list()

    def __init__(self):
        self.wrapped = wrapped

    def __call__(self, wrapped):
        self.wrapped = wrapped
        self.INSTANCE_PATHS.append(wrapped.__module__ + ',' + wrapped.__name__)
        return self._decor

    def _decor(self, args, kwargs):
        return self.wrapped(*args, **kwargs)
```

